+    ASSERT_EQ(st, ASX_OK);
+
+    st = asx_task_get_state(tid, &tstate);
+    ASSERT_EQ(st, ASX_OK);
+    ASSERT_EQ(tstate, ASX_TASK_COMPLETED);
+
+    ASSERT_EQ(ctx.remaining, 0);
+}
