+TEST(multiple_tasks_in_region)
+{
+    asx_region_id rid;
+    asx_task_id tid1, tid2, tid3;
+    asx_task_state ts1, ts2, ts3;
+    asx_outcome o1, o2, o3;
+    asx_budget budget;
+    asx_status st;
+    countdown_ctx ctx1, ctx2;
+
+    ctx1.remaining = 1;
+    ctx2.remaining = 2;
+
